#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    int totalNQueens(int n) {
        vector<vector<bool>> board(n, vector<bool>(n, false));
        return placeQueens(n, 0);
    }

    int placeQueens(int n, int col) {
        if (col == n) return 1;
        int total = 0;
        for (int i = 0; i < n; ++i) {
            if (isValid(board, i, col)) {
                board[i][col] = true;
                total += placeQueens(n, col + 1);
                board[i][col] = false;
            }
        }
        return total;
    }

    bool isValid(vector<vector<bool>>& board, int row, int col) {
        for (int i = 0; i < row; ++i) {
            if (board[i][col]) return false;
        }
        for (int i = row - 1, j = col - 1; i >= 0 && j >= 0; --i, --j) {
            if (board[i][j]) return false;
        }
        for (int i = row - 1, j = col + 1; i >= 0 && j < board.size(); --i, ++j) {
            if (board[i][j]) return false;
        }
        return true;
    }
};

int main() {
    int n;
    cin >> n;
    Solution solution;
    cout << solution.totalNQueens(n) << endl;
    return 0;
}
